# InventFlow Clean Professional Design - One-Shot Script

$root = "D:\inventory-system\inventory-system"

if (!(Test-Path $root)) {
    Write-Host "ERROR: Project not found at $root" -ForegroundColor Red
    exit 1
}

Write-Host ""
Write-Host "InventFlow Clean Design Refresh" -ForegroundColor Cyan
Write-Host "================================" -ForegroundColor Cyan
Write-Host ""
Write-Host "[1/3] Writing design files..." -ForegroundColor Yellow

# index.css
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$path = $root + "\frontend\src\index.css"
$dir = Split-Path $path -Parent
if (!(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
[System.IO.File]::WriteAllBytes($path, $bytes)
Write-Host "  [OK] index.css" -ForegroundColor Green

# App.js
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$path = $root + "\frontend\src\App.js"
$dir = Split-Path $path -Parent
if (!(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
[System.IO.File]::WriteAllBytes($path, $bytes)
Write-Host "  [OK] App.js" -ForegroundColor Green

# Dashboard.js
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$path = $root + "\frontend\src\pages\Dashboard.js"
$dir = Split-Path $path -Parent
if (!(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
[System.IO.File]::WriteAllBytes($path, $bytes)
Write-Host "  [OK] Dashboard.js" -ForegroundColor Green

# Products.js
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$path = $root + "\frontend\src\pages\Products.js"
$dir = Split-Path $path -Parent
if (!(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
[System.IO.File]::WriteAllBytes($path, $bytes)
Write-Host "  [OK] Products.js" -ForegroundColor Green

# Customers.js
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$path = $root + "\frontend\src\pages\Customers.js"
$dir = Split-Path $path -Parent
if (!(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
[System.IO.File]::WriteAllBytes($path, $bytes)
Write-Host "  [OK] Customers.js" -ForegroundColor Green

# Orders.js
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$path = $root + "\frontend\src\pages\Orders.js"
$dir = Split-Path $path -Parent
if (!(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
[System.IO.File]::WriteAllBytes($path, $bytes)
