Write-Host ""
Write-Host "[2/3] Rebuilding Docker frontend (takes ~2-3 minutes)..." -ForegroundColor Yellow
Set-Location $root
docker compose stop frontend 2>&1 | Out-Host
docker compose build frontend

Write-Host ""
Write-Host "[3/3] Starting frontend container..." -ForegroundColor Yellow
docker compose up -d frontend

Write-Host ""
Write-Host "================================================" -ForegroundColor Green
Write-Host "  DONE! Open http://localhost:3000" -ForegroundColor Green
Write-Host "  Use Ctrl+Shift+R to bypass browser cache." -ForegroundColor Green
Write-Host "================================================" -ForegroundColor Green